import React, { useEffect, useState } from "react";

import { ICategory, IColor, ISettings, ISize } from "../types/types";
import api from "../components/api";
const SETTINGS_TIME_KEY = "settings_time";
const COLORS_KEY = "colors";
const SIZES_KEY = "sizes";
const CATEGORIES_KEY = "categories";


const settingsService = async (): Promise<ISettings> => {
  const response = await api.get("/v1/settings");
  return response.data;
};

const useSettings = () => {
  const [colors, setColors] = useState<IColor[]>([]);
  const [sizes, setSizes] = useState<ISize[]>([]);
  const [categories, setCategories] = useState<ICategory[]>([]);

  useEffect(() => {
    const oldTime: number = parseInt(sessionStorage.getItem(SETTINGS_TIME_KEY) || "");
    const now: number = Date.now();
    const exp = 10 * 1000 * 60; // 10 minutes

    // call settings api if is first time (!oldTime) OR if the time has expired
    if (!oldTime || now - oldTime > exp) {
      settingsService().then((res) => {
        // save in session storage
        StoreSettings.updateSettings(now, res.colors, res.sizes, res.categories);

        // save in states
        setColors(res.colors);
        setSizes(res.sizes);
        setCategories(res.categories);
      }).catch((err) => {
        console.log(err);
      });
    } else {
        setColors(StoreSettings.getColors());
        setSizes(StoreSettings.getSizes());
        setCategories(StoreSettings.getCategories());
    }

  }, [])

  return { colors, sizes, categories }
}
export default useSettings;


class StoreSettings {

  public static updateSettings(time: number, colors: IColor[], sizes: ISize[], categories: ICategory[]) {
    sessionStorage.setItem(SETTINGS_TIME_KEY, time.toString());
    sessionStorage.setItem(COLORS_KEY, JSON.stringify(colors));
    sessionStorage.setItem(SIZES_KEY, JSON.stringify(sizes));
    sessionStorage.setItem(CATEGORIES_KEY, JSON.stringify(categories));
  }

  public static getColors(): IColor[] {
    const storedColors = sessionStorage.getItem(COLORS_KEY);
    return storedColors ? JSON.parse(storedColors) : [];
  }

  public static getSizes(): ISize[] {
    const storedSizes = sessionStorage.getItem(SIZES_KEY);
    return storedSizes ? JSON.parse(storedSizes) : [];
  }

  public static getCategories(): ICategory[] {
    const storedCategories = sessionStorage.getItem(CATEGORIES_KEY);
    return storedCategories ? JSON.parse(storedCategories) : [];
  }

}
