import React from "react";
import useSettings from "../../storage/useSettings";
import { Box, Button } from "@mui/material";

type SelectSizeProps = {
    selectedSizeId: number | undefined;
    onSelectSize: (sizeId: number) => void;
}

const SelectSize = ({ selectedSizeId, onSelectSize }: SelectSizeProps) => {
    const { sizes } = useSettings();
    return (
        <Box gap={2} mt={4} display='flex' flexWrap='wrap'>
            {sizes.map((size) => (
                <Button
                    key={size.id}
                    onClick={() => onSelectSize(size.id)}
                    variant={size.id === selectedSizeId ? "contained" : "outlined"}
                >
                    {size.name}
                </Button>
            ))}
        </Box>
    )
}

export default SelectSize;
